            'lenderBankInn' => $bankInn,
            'payment_date' => $user_balance && !empty($user_balance->payment_date) ? $user_balance->payment_date : date('Y-m-d'),
            'overdue_date' => (new DateTime($user_balance && !empty($user_balance->payment_date) ? $user_balance->payment_date : date('Y-m-d')))->modify('+1 day'),
            'zaim_number' => $user_balance ? $user_balance->zaim_number : '',
