    /**
     * Создает PDF документ соглашения АСП
     * @param Object $user
     * @param int $order_id
     * @param string|null $sms
     * @param bool $storeToDb
     * @param int|null $crossOrganizationId
     * @return bool
     */
    public function getAspAgreementPdf(Object $user, int $order_id, string $sms = null, bool $storeToDb = false, ?int $crossOrganizationId = null): bool
    {
        $params = $this->getAspAgreementParams($user, $order_id, $sms, null, $crossOrganizationId);
        $order = $this->orders->get_order($order_id);
        $tpl = ($params['organization_id'] ?? -1) == $this->organizations::FASTFINANCE_ID ? Documents::ASP_AGREEMENT_FASTFINANCE : Documents::ASP_AGREEMENT;

        if ($storeToDb) {
            return $this->documents->create_document([
                'order_id' => $order_id,
                'user_id' => $user->id,
                'contract_number' => $order->id,
                'type' => $tpl,
                'params' => $params,
            ]);
        }

        $this->createDocumentForType($params, $tpl);

        return true;
    }

    /**
     * Подготавливает шаблон, заголовок и имя файла для документа на основе переданных параметров и типа
     *
     * @param array $params Параметры для шаблона
     * @param string $type Тип документа
     * @return array
     */
    public function prepareDocumentData(array $params, string $type): array
    {
        $this->design->assignBulk($params);

        $contractParams = $this->documents->get_document_params();
        $tplName = $contractParams[$type][Documents::KEY_TEMPLATE];
        $title = $contractParams[$type][Documents::KEY_NAME];

        $tpl = $this->design->fetch('pdf/' . $tplName);

        return [
            'template' => $tpl,
            'title'    => $title,
            'filename' => $tplName
        ];
    }

    /**
     * Создаёт PDF-документ из шаблона.
     *
     * @param array $params Данные для шаблона
     * @param string $type Тип документа
     * @param string|null $filename Имя файла (если сохраняется)
     * @param string|null $path Путь сохранения
     * @param bool $save Сохранять ли файл
     * @return void
     */
    public function createDocumentForType(array $params, string $type, ?string $filename = null, ?string $path = null, bool $save = false): void
    {
        $this->organizations->assign_to_design();
        $doc = $this->prepareDocumentData($params, $type);

        $this->pdf->create(
            $doc['template'],
            $doc['title'],
            $filename ?? $doc['filename'],
            $save,
            ['path' => $path]
        );
    }

    /**
     * Генерирует PDF-документ во временный файл, возвращает его бинарное содержимое.
     *
     * @param string $contractNumber Номер договора
     * @param string $type Тип документа
     * @return string Путь к PDF-файлу
     * @throws Exception При ошибке чтения или сериализации
     */
    public function generateDocumentPdfToFile(string $contractNumber, string $type): string
    {
        $rawParams = $this->documents->getDocument($type, $contractNumber)->params;

        $params = unserialize($rawParams);

        $doc = $this->prepareDocumentData((array) $params, $type);

        $fileName = uniqid('doc_') . '.pdf';
        $customPath = dirname(__DIR__) . '/files/extras_documents';

        $this->pdf->create($doc['template'], $doc['title'], $fileName, true, ['path' => $customPath]);
        $this->pdf->reset();

        return rtrim($customPath, DIRECTORY_SEPARATOR) . DIRECTORY_SEPARATOR . $fileName;
    }


    /**
     * @param Object $user
     * @param int $order_id
     * @param string|null $sms
     * @param string|null $sign_date
     * @param int|null $crossOrganizationId
     * @return array
     */
    public function getOfferAgreementParams(Object $user, int $order_id, ?string $sms = null, ?string $sign_date = null, ?int $crossOrganizationId = null): array
    {
        $order = $this->orders->get_order($order_id);
        $orgId = $crossOrganizationId ?: $order->organization_id;
        $organization = $this->organizations->get_organization($orgId);

        // Адрес регистрации заемщика
        $addressReg = trim(sprintf(
            '%s %s, %s, ул. %s, д. %s, кв. %s',
            $user->Regindex,
            $user->Regregion,
            $user->Regcity,
            $user->Regstreet,
            $user->Reghousing,
            $user->Regroom
        ));

        $user_passport_split = $this->helpers::splitPassportSerial($user->passport_serial);
        try {
            $user_balance = $this->users->get_user_balance_for_order($user->id, $order->id_1c);
        } catch (Exception $e) {
            $user_balance = null;
        }

        if (!$sign_date) {
            $sign_date = $user_balance->zaim_date === '0001-01-01T00:00:00' ? date('Y-m-d H:i:s')
                : $user_balance->zaim_date;
        }

        return [
            'full_name' => $this->helpers::getFIO($user),
            'email' => $user->email,
            'phone' => $user->phone_mobile,
            'passport_serial' => $user_passport_split['serial'],
            'passport_number' => $user_passport_split['number'],
            'passport_date' => $user->passport_date,
            'passport_issued' => $user->passport_issued,
            'subdivision_code' => $user->subdivision_code,
            'registration_address' => $addressReg,
            'organization_name' => $organization->name,
            'organization_ogrn' => $organization->ogrn,
            'zaim_number' => $user_balance->zaim_number,
            'zaim_date' => $user_balance->zaim_date,
            'organization_site' => $organization->site,
            'organization_address_post' => $organization->address, //Почтовый
            'organization_director' => $organization->director ?? 'Поздняковa С.В.',
            'organization_address_req' => $organization->address, //Регистрации
            'organization_email' => $organization->email,
            'plaintiff_name' => 'ООО ПКО "ПРАВОВАЯ ЗАЩИТА"',
            'plaintiff_site' => 'https://pravza.com/',
            'accept_sms' => $sms ?? $order->accept_sms,
            'order_signed' => $order->status_1c === '5.Выдан',
            'organization_id' => $organization->id,
            'sign_date' => $sign_date,
        ];
    }

    /**
     * @param Object $user
     * @param int $order_id
     * @param string|null $sms
     * @param bool $storeToDb
     * @param int|null $crossOrganizationId
     * @return bool
     */
    public function getOfferAgreementPdf(Object $user, int $order_id, string  $sms = null, bool $storeToDb = false, ?int $crossOrganizationId = null): bool
    {
        $params = $this->getOfferAgreementParams($user, $order_id, $sms, null, $crossOrganizationId);
